import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine().trim(); // Read a full line and remove leading/trailing whitespaces

        int bufferSize = 10;

        // Check if user input exceeds buffer size
        if (userInput.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Please enter a string with maximum length of " + bufferSize);
            return;
        }

        char[] buffer = new char[bufferSize]; // Fixed size buffer

        // Copy user input into the buffer
        for (int i = 0; i < userInput.length(); i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Buffer overflow vulnerability successfully mitigated!");
    }
}

